import { useState } from "react";

const I = {"nessa": "data:image/jpeg;base64,", "rylie": "data:image/jpeg;base64,", "georgie": "data:image/jpeg;base64,", "sofia": "data:image/jpeg;base64,", "bronwen": "data:image/jpeg;base64,", "kelce": "data:image/jpeg;base64,", "juicy": "data:image/jpeg;base64,", "lara": "data:image/jpeg;base64,", "klara": "data:image/jpeg;base64,", "juicy_royal": "data:image/jpeg;base64,", "logo": "data:image/png;base64,"};

const P = [
  {id:1,name:"Nessa Backpack",brand:"GUESS",color:"Light Rose",price:70,orig:88,type:"Mochila",img:I.nessa,sold:false,desc:"Mochila con estampado all-over logo G y parche circular GUESS Los Angeles. Hardware plateado con charm de flor."},
  {id:2,name:"Rylie Mini Crossbody",brand:"Tommy Hilfiger",color:"Beige/Brown",price:78,orig:98,type:"Crossbody",img:I.rylie,sold:false,desc:"Mini crossbody con patrón de rayas, solapa frontal con logo TH dorado y correa ajustable de cuero."},
  {id:3,name:"Georgie Tote",brand:"Tommy Hilfiger",color:"Black Tonal",price:104,orig:130,type:"Tote",img:I.georgie,sold:false,desc:"Tote elegante con patrón de diamantes monograma TH, placa dorada central y asas dobles."},
  {id:4,name:"Sofia Tote",brand:"GUESS",color:"Almond",price:86,orig:108,type:"Tote",img:I.sofia,sold:false,desc:"Tote estructurado con estampado all-over logo G, barra frontal metálica con letras GUESS."},
  {id:5,name:"Bronwen Shoulder",brand:"GUESS",color:"Vanilla",price:70,orig:88,type:"Shoulder",img:I.bronwen,sold:false,desc:"Bolso de hombro quilted con letras doradas GUESS Los Angeles y cadena dorada decorativa."},
  {id:6,name:"Kelce Crossbody Flap",brand:"GUESS",color:"Cream",price:70,orig:88,type:"Crossbody",img:I.kelce,sold:false,desc:"Crossbody con estampado all-over G, franja central, cadena dorada y letras GUESS."},
  {id:7,name:"Juicy in the Sky Satchel",brand:"Juicy Couture",color:"Soft Pink",price:71,orig:89,type:"Satchel",img:I.juicy,sold:false,desc:"Satchel con logo Juicy bordado, mariposas y flores decorativas, charm de corazón dorado."},
  {id:8,name:"Lara All Over Logo",brand:"GUESS",color:"Rose",price:70,orig:88,type:"Crossbody",img:I.lara,sold:false,desc:"Crossbody compacto con estampado all-over logo G en tono rosado, correa ajustable."},
  {id:9,name:"Klara Rhine Logo",brand:"Steve Madden",color:"Pearl White",price:70,orig:88,type:"Shoulder",img:I.klara,sold:false,desc:"Bolso con logo STEVE MADDEN embossed, cadena dorada, charms de candado y tacón."},
  {id:10,name:"Royal Camera Crossbody",brand:"Juicy Couture",color:"Black/Cream",price:71,orig:89,type:"Crossbody",img:I.juicy_royal,sold:false,desc:"Crossbody en terciopelo negro con corona de cristales, bordado Juicy Couture Royal, mini cartera incluida."},
  {id:11,name:"Tabby Shoulder Bag 26",brand:"Coach",color:"Black",price:360,orig:450,type:"Shoulder",img:null,sold:true,desc:"Icónico bolso de hombro en pebble leather con hardware C dorado, correa desmontable y cierre snap."},
  {id:12,name:"Jet Set Travel Tote",brand:"Michael Kors",color:"Vanilla",price:238,orig:298,type:"Tote",img:null,sold:true,desc:"Tote clásico en cuero Saffiano con logo MK, bolsillo exterior y cierre superior con cremallera."},
  {id:13,name:"Knott Medium Satchel",brand:"Kate Spade",color:"Black",price:318,orig:398,type:"Satchel",img:null,sold:true,desc:"Satchel de cuero suave con diseño minimalista, asas superiores y correa crossbody desmontable."},
  {id:14,name:"Brooklyn Shoulder Bag",brand:"Coach",color:"Chalk",price:316,orig:395,type:"Shoulder",img:null,sold:true,desc:"Bolso de hombro en cuero suave con cadena dorada, estilo boho-chic, ideal para día y noche."},
  {id:15,name:"Kensington Crossbody",brand:"Michael Kors",color:"Soft Pink",price:206,orig:258,type:"Crossbody",img:null,sold:true,desc:"Crossbody quilted en cuero con cadena dorada, cierre giratorio MK y correa ajustable."},
];

const BRANDS=["Todas","GUESS","Tommy Hilfiger","Juicy Couture","Steve Madden","Coach","Michael Kors","Kate Spade"];
const TYPES=["Todos","Tote","Crossbody","Shoulder","Mochila","Satchel"];
const PH="51933109845";
const bc={"GUESS":["#b8860b","#d4a744"],"Tommy Hilfiger":["#1a3668","#2c5aa0"],"Juicy Couture":["#c46b92","#e8a0bf"],"Steve Madden":["#5c4033","#8b6914"],"Coach":["#8B4513","#CD853F"],"Michael Kors":["#333","#666"],"Kate Spade":["#2d5016","#5a9e3a"]};
const be={"GUESS":"✨","Tommy Hilfiger":"🏁","Juicy Couture":"🎀","Steve Madden":"👠","Coach":"🐎","Michael Kors":"💎","Kate Spade":"♠️"};

export default function LucyShop(){
  const[brand,setBrand]=useState("Todas");
  const[type,setType]=useState("Todos");
  const[modal,setModal]=useState(null);

  const f=P.filter(p=>{
    if(brand!=="Todas"&&p.brand!==brand)return false;
    if(type!=="Todos"&&p.type!==type)return false;
    return true;
  });
  const av=f.filter(p=>!p.sold);
  const so=f.filter(p=>p.sold);
  const all=[...av,...so];

  const wa=p=>{const m=encodeURIComponent(`¡Hola Lucy Shop! 💕 Me interesa: ${p.name} (${p.brand}) - ${p.color}. ¿Está disponible?`);window.open(`https://wa.me/${PH}?text=${m}`,"_blank")};

  return(
    <div style={{background:'#fef6f0',minHeight:'100vh',fontFamily:"'Quicksand',sans-serif"}}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700;800;900&family=Quicksand:wght@300;400;500;600;700&display=swap');
        *{margin:0;padding:0;box-sizing:border-box}
        body{background:#fef6f0;overflow-x:hidden}
        @keyframes fadeUp{from{opacity:0;transform:translateY(24px)}to{opacity:1;transform:translateY(0)}}
        @keyframes slideIn{from{opacity:0;transform:scale(.95)}to{opacity:1;transform:scale(1)}}
        @keyframes pulse{0%,100%{opacity:1}50%{opacity:.7}}
        .card{animation:fadeUp .5s ease both;transition:all .35s cubic-bezier(.23,1,.32,1);cursor:pointer}
        .card:hover{transform:translateY(-6px);box-shadow:0 24px 48px rgba(200,160,180,.25)}
        .card-sold{animation:fadeUp .5s ease both;transition:all .35s ease;cursor:pointer}
        .card-sold:hover{transform:translateY(-3px);box-shadow:0 12px 24px rgba(0,0,0,.08)}
        .fb{transition:all .25s ease;cursor:pointer;border:none;outline:none}
        .fb:hover{transform:translateY(-1px)}
        .wb{transition:all .25s ease;cursor:pointer}
        .wb:hover{transform:scale(1.04);box-shadow:0 8px 24px rgba(37,211,102,.35)}
        .ov{position:fixed;inset:0;background:rgba(0,0,0,.55);backdrop-filter:blur(10px);display:flex;align-items:center;justify-content:center;z-index:999;padding:16px}
        .md{background:#fff;border-radius:20px;max-width:440px;width:100%;overflow:hidden;animation:slideIn .25s ease;max-height:92vh;overflow-y:auto}
        .sb{animation:pulse 2s ease-in-out infinite}
      `}</style>

      {/* HERO */}
      <div style={{background:'linear-gradient(145deg,#fce4ec 0%,#f8c8dc 25%,#e8a0bf 50%,#c5cae9 75%,#b3e5fc 100%)',position:'relative',overflow:'hidden'}}>
        <div style={{position:'absolute',inset:0,background:'radial-gradient(circle at 20% 30%,rgba(255,255,255,.3) 0%,transparent 50%),radial-gradient(circle at 80% 70%,rgba(255,255,255,.2) 0%,transparent 50%)'}}/>
        <div style={{position:'relative',zIndex:1,textAlign:'center'}}>
          <img src={I.logo} alt="Lucy Shop" style={{width:'100%',maxWidth:'100%',display:'block',margin:'0 auto',objectFit:'contain'}}/>
          <div style={{background:'rgba(255,255,255,.88)',backdropFilter:'blur(12px)',padding:'16px 0',display:'flex',justifyContent:'center',gap:32,flexWrap:'wrap'}}>
            {[["10+","Productos"],["5","Marcas"],["100%","Originales"],["📱","WhatsApp"]].map(([n,l],i)=>(
              <div key={i} style={{textAlign:'center',minWidth:70}}>
                <div style={{fontFamily:"'Playfair Display',serif",fontSize:22,fontWeight:800,color:'#c4956a'}}>{n}</div>
                <div style={{fontSize:10,color:'#888',letterSpacing:1.5,textTransform:'uppercase',fontWeight:600}}>{l}</div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* PROMO BANNER */}
      <div style={{background:'linear-gradient(135deg,#e53e3e,#c53030)',padding:'14px 20px',textAlign:'center'}}>
        <p style={{fontFamily:"'Quicksand',sans-serif",color:'#fff',fontSize:14,fontWeight:700,margin:0,letterSpacing:.5}}>🔥 PROMO AL CONTADO: <span style={{fontSize:16}}>20% OFF</span> en todos los productos 🔥</p>
      </div>

      {/* FILTERS */}
      <div style={{maxWidth:960,margin:'0 auto',padding:'24px 16px 8px'}}>
        <h2 style={{fontFamily:"'Playfair Display',serif",fontSize:18,color:'#2d1b30',marginBottom:10,fontWeight:700}}>✨ Explorar por marca</h2>
        <div style={{display:'flex',flexWrap:'wrap',gap:8,marginBottom:16}}>
          {BRANDS.map(b=>(
            <button key={b} className="fb" onClick={()=>setBrand(b)} style={{fontFamily:"'Quicksand',sans-serif",padding:'10px 20px',borderRadius:50,fontSize:12,fontWeight:700,background:brand===b?'linear-gradient(135deg,#e8a0bf,#f8c8dc)':'white',color:brand===b?'#fff':'#777',boxShadow:brand===b?'0 4px 16px rgba(232,160,191,.4)':'0 2px 8px rgba(0,0,0,.05)'}}>{be[b]||"🛍"} {b}</button>
          ))}
        </div>
        <h2 style={{fontFamily:"'Playfair Display',serif",fontSize:18,color:'#2d1b30',marginBottom:10,fontWeight:700}}>👜 Tipo de bolso</h2>
        <div style={{display:'flex',flexWrap:'wrap',gap:8}}>
          {TYPES.map(t=>(
            <button key={t} className="fb" onClick={()=>setType(t)} style={{fontFamily:"'Quicksand',sans-serif",padding:'8px 18px',borderRadius:50,fontSize:12,fontWeight:600,background:'transparent',color:type===t?'#c4956a':'#aaa',border:type===t?'2px solid #c4956a':'1.5px solid #e0d8d4'}}>{t}</button>
          ))}
        </div>
      </div>

      {/* PRODUCTS */}
      <div style={{maxWidth:960,margin:'0 auto',padding:'16px 16px 48px'}}>
        <p style={{fontSize:13,color:'#bbb',marginBottom:16,fontWeight:500}}>{f.length} producto{f.length!==1?'s':''} · {av.length} disponible{av.length!==1?'s':''}</p>
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(270px,1fr))',gap:20}}>
          {all.map((p,i)=>(
            <div key={p.id} className={p.sold?"card-sold":"card"} style={{background:'#fff',borderRadius:18,overflow:'hidden',boxShadow:'0 4px 20px rgba(0,0,0,.05)',animationDelay:`${i*.08}s`,opacity:p.sold?.65:1,filter:p.sold?'saturate(0.3)':'none'}} onClick={()=>setModal(p)}>
              <div style={{position:'relative',height:280,background:p.sold?'linear-gradient(135deg,#e8e4e0,#d8d4d0)':'linear-gradient(135deg,#faf6f3,#f2ebe5)',overflow:'hidden'}}>
                {p.img?(<img src={p.img} alt={p.name} style={{width:'100%',height:'100%',objectFit:'cover',filter:p.sold?'grayscale(.5)':''}}/>):(<div style={{width:'100%',height:'100%',display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center'}}><span style={{fontSize:48}}>{p.sold?'🔒':'👜'}</span><span style={{fontSize:11,color:'#bbb',marginTop:8}}>{p.sold?'Producto agotado':'Foto próximamente'}</span></div>)}
                <span style={{position:'absolute',top:12,left:12,fontFamily:"'Quicksand',sans-serif",fontWeight:700,fontSize:10,letterSpacing:1.5,textTransform:'uppercase',padding:'5px 14px',borderRadius:20,color:'#fff',background:`linear-gradient(135deg,${(bc[p.brand]||['#888','#aaa'])[0]},${(bc[p.brand]||['#888','#aaa'])[1]})`}}>{p.brand}</span>
                <span style={{position:'absolute',bottom:12,right:12,background:'rgba(255,255,255,.9)',backdropFilter:'blur(4px)',padding:'4px 12px',borderRadius:20,fontSize:11,fontWeight:600,color:'#888'}}>{p.type}</span>
                {!p.sold&&(<span style={{position:'absolute',top:12,right:12,background:'linear-gradient(135deg,#e53e3e,#c53030)',color:'#fff',fontFamily:"'Quicksand',sans-serif",fontWeight:800,fontSize:12,padding:'6px 12px',borderRadius:20,boxShadow:'0 2px 10px rgba(229,62,62,.4)',animation:'pulse 2s infinite'}}>-20%</span>)}
                {p.sold&&(<div className="sb" style={{position:'absolute',top:'50%',left:'50%',transform:'translate(-50%,-50%) rotate(-12deg)',background:'rgba(180,30,30,.9)',color:'white',padding:'10px 28px',borderRadius:8,fontFamily:"'Playfair Display',serif",fontSize:18,fontWeight:800,letterSpacing:2,textTransform:'uppercase',boxShadow:'0 4px 20px rgba(180,30,30,.3)',border:'2px solid rgba(255,255,255,.3)'}}>AGOTADO</div>)}
              </div>
              <div style={{padding:'14px 18px 18px'}}>
                <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:16,fontWeight:700,color:p.sold?'#999':'#2d1b30',marginBottom:3}}>{p.name}</h3>
                <p style={{fontSize:12,color:'#aaa',fontWeight:500,marginBottom:14}}>Color: {p.color}</p>
                <div style={{display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                  <div style={{display:'flex',alignItems:'baseline',gap:8}}>{!p.sold&&(<span style={{fontFamily:"'Quicksand',sans-serif",fontSize:14,fontWeight:600,color:'#bbb',textDecoration:'line-through'}}>${p.orig}</span>)}<span style={{fontFamily:"'Playfair Display',serif",fontSize:24,fontWeight:800,color:p.sold?'#ccc':'#c4956a',textDecoration:p.sold?'line-through':'none'}}>${p.price}</span></div>
                  {p.sold?(<span style={{fontSize:11,color:'#c44',fontWeight:700,fontFamily:"'Quicksand',sans-serif",background:'#fde8e8',padding:'6px 14px',borderRadius:20}}>No disponible</span>):(<button className="wb" onClick={e=>{e.stopPropagation();wa(p)}} style={{background:'#25D366',color:'#fff',border:'none',padding:'8px 18px',borderRadius:50,fontSize:12,fontWeight:700,fontFamily:"'Quicksand',sans-serif"}}>💬 Consultar</button>)}
                </div>
              </div>
            </div>
          ))}
        </div>
        {f.length===0&&(<div style={{textAlign:'center',padding:60}}><span style={{fontSize:56}}>🔍</span><p style={{color:'#bbb',marginTop:12}}>No hay productos con estos filtros</p></div>)}
      </div>

      {/* MODAL */}
      {modal&&(
        <div className="ov" onClick={()=>setModal(null)}>
          <div className="md" onClick={e=>e.stopPropagation()}>
            {modal.img?(<img src={modal.img} alt={modal.name} style={{width:'100%',height:320,objectFit:'cover',filter:modal.sold?'grayscale(.4) brightness(.85)':''}}/>):(<div style={{width:'100%',height:200,display:'flex',alignItems:'center',justifyContent:'center',background:modal.sold?'linear-gradient(135deg,#e0dcd8,#ccc)':'linear-gradient(135deg,#faf6f3,#f2ebe5)'}}><span style={{fontSize:64}}>{modal.sold?'🔒':'👜'}</span></div>)}
            <div style={{padding:24}}>
              <div style={{display:'flex',alignItems:'center',gap:8,flexWrap:'wrap'}}>
                <span style={{fontFamily:"'Quicksand',sans-serif",fontWeight:700,fontSize:10,letterSpacing:1.5,textTransform:'uppercase',padding:'5px 14px',borderRadius:20,color:'#fff',display:'inline-block',background:`linear-gradient(135deg,${(bc[modal.brand]||['#888','#aaa'])[0]},${(bc[modal.brand]||['#888','#aaa'])[1]})`}}>{modal.brand}</span>
                {modal.sold&&<span style={{fontSize:10,fontWeight:700,color:'#c44',background:'#fde8e8',padding:'5px 12px',borderRadius:20}}>AGOTADO</span>}
              </div>
              <h2 style={{fontFamily:"'Playfair Display',serif",fontSize:26,color:'#2d1b30',marginTop:12,fontWeight:800}}>{modal.name}</h2>
              <p style={{fontSize:13,color:'#999',margin:'6px 0'}}>Color: {modal.color} · Tipo: {modal.type}</p>
              <div style={{display:'flex',alignItems:'center',gap:12,margin:'14px 0'}}>{!modal.sold&&(<span style={{fontFamily:"'Quicksand',sans-serif",fontSize:18,fontWeight:600,color:'#bbb',textDecoration:'line-through'}}>${modal.orig}.00</span>)}<span style={{fontFamily:"'Playfair Display',serif",fontSize:34,color:modal.sold?'#ccc':'#c4956a',fontWeight:800,textDecoration:modal.sold?'line-through':'none'}}>${modal.price}.00</span>{!modal.sold&&(<span style={{background:'linear-gradient(135deg,#e53e3e,#c53030)',color:'#fff',fontFamily:"'Quicksand',sans-serif",fontWeight:800,fontSize:13,padding:'5px 14px',borderRadius:20}}>-20% OFF</span>)}</div>
              <p style={{fontSize:13,color:'#aaa',lineHeight:1.7,marginBottom:20}}>{modal.desc}</p>
              <div style={{display:'flex',gap:10}}>
                {modal.sold?(<button className="wb" onClick={()=>{const m=encodeURIComponent(`¡Hola Lucy Shop! 💕 Vi que la ${modal.name} (${modal.brand}) está agotada. ¿Tendrán restock pronto?`);window.open(`https://wa.me/${PH}?text=${m}`,"_blank")}} style={{flex:1,background:'linear-gradient(135deg,#e8a0bf,#f8c8dc)',color:'#fff',border:'none',padding:'14px',borderRadius:50,fontSize:14,fontWeight:700,fontFamily:"'Quicksand',sans-serif"}}>🔔 Avisar cuando llegue</button>):(<button className="wb" onClick={()=>wa(modal)} style={{flex:1,background:'#25D366',color:'#fff',border:'none',padding:'14px',borderRadius:50,fontSize:15,fontWeight:700,fontFamily:"'Quicksand',sans-serif"}}>💬 Pedir por WhatsApp</button>)}
                <button onClick={()=>setModal(null)} style={{background:'#f0e8e4',border:'none',width:50,height:50,borderRadius:50,fontSize:18,color:'#999',cursor:'pointer'}}>✕</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* FOOTER */}
      <div style={{background:'linear-gradient(135deg,#2d1b30,#4a2d4a)',padding:'36px 20px',textAlign:'center'}}>
        <div style={{fontSize:28,fontFamily:"'Playfair Display',serif",fontWeight:800,color:'#f8c8dc',marginBottom:8}}>Lucy Shop</div>
        <p style={{color:'rgba(255,255,255,.6)',fontSize:13,marginBottom:20}}>Carteras originales de las mejores marcas ✨</p>
        <button className="wb" onClick={()=>window.open(`https://wa.me/${PH}`,"_blank")} style={{background:'linear-gradient(135deg,#25D366,#128C7E)',color:'#fff',border:'none',padding:'14px 36px',borderRadius:50,fontSize:14,fontWeight:700,fontFamily:"'Quicksand',sans-serif",cursor:'pointer'}}>📱 Contáctanos: {PH}</button>
        <p style={{color:'rgba(255,255,255,.3)',fontSize:10,marginTop:20}}>© 2026 Lucy Shop · Todos los derechos reservados</p>
      </div>
    </div>
  );
}
